INSERT INTO medicines (id, name, generic_name, category_id, dosage_form_id, therapeutic_class, schedule, need_manual_review, dose_value, dose_unit, regulatory_code, requires_prescription, indications, contraindications, side_effects, dosage_instructions, pregnancy_category, image_url) VALUES ('c025df97-c01f-53c6-95bf-a174fea0f5a0', 'Sumatriptan', 'Sumatriptan', 'c9bbfdff-886b-5b0b-bc80-b0b516f0d977', '6e890b3b-4147-5584-9021-fda6f1e1d68c', 'Antimigraine Medicines*', NULL, FALSE, '25', 'mg', 'EFDA-NS200-0011', TRUE, 'Sumatriptan FDA approval is for the treatment of adults with: Acute migraine headaches with or without aura - tablets, capsules, nasal spray, and injection Acute cluster headache - injection only This medicine should only be used if there has been a clear diagnosis of migraine headache. If there is no response to the first migraine attack treated with sumatriptan succinate, then reconsider the diagnosis of migraine before it is administered to treat any further migraine attacks. The safety and effectiveness of oral or nasal sumatriptan succinate for cluster headaches have not been established.&nbsp; Sumatriptan succinate should not be used to treat a common tension headache or a headache that causes loss of movement on one side of your body. Use this medicine only if your condition has been confirmed by a doctor as migraine headaches.', NULL, NULL, NULL, NULL, NULL);
