INSERT INTO medicines (id, name, generic_name, category_id, dosage_form_id, therapeutic_class, schedule, need_manual_review, dose_value, dose_unit, regulatory_code, requires_prescription, indications, contraindications, side_effects, dosage_instructions, pregnancy_category, image_url) VALUES ('33934c1b-5617-537d-aace-c8603a08807b', 'Sulfasalazine', 'Sulfasalazine', '08f28836-5e50-5d50-b821-8e242c3d8949', '6e890b3b-4147-5584-9021-fda6f1e1d68c', 'Diseases Modifying Antirheumatic Medicines', NULL, FALSE, '500', 'mg', 'EFDA-MS300-0003', TRUE, 'Sulfasalazine is a prescription medication that is available as a standard tablet and as a delay-release, enteric-coated tablet. Standard sulfasalazine tablets are used: to treat mild to moderate ulcerative colitis. as an add-on (adjunctive) therapy in severe ulcerative colitis. to prolong periods of remission between acute attacks of ulcerative colitis. Delay-release, enteric-coated sulfasalazine tablets are used: to treat mild to moderate ulcerative colitis, particularly in patients who cannot take standard, uncoated sulfasalazine tablets because of gastrointestinal side effects that are not caused by high blood levels of sulfapyridine and its metabolites. This includes patients who experience nausea and vomiting with the first few doses and patients who continue to have symptoms when their dose is reduced as an add-on (adjunctive) therapy in severe ulcerative colitis to prolong periods of remission between acute attacks of ulcerative colitis to treat rheumatoid arthritis in patients who have responded inadequately to salicylates or other nonsteroidal anti-inflammatory drugs (NSAIDs) to treat children with polyarticular-course juvenile rheumatoid arthritis who have responded inadequately to salicylates or other NSAIDs. Because sulfasalazine does not produce an immediate response, other analgesics and/or NSAIDs may still be needed until sulfasalazine starts working. Sulfasalazine is also used ''off-label'' - for conditions it is not approved for, such as ankylosing spondylitis, Crohn''s disease, and psoriatic arthritis. It is not known if sulfasalazine is safe and effective in children below the age of 2 years old.', NULL, NULL, NULL, NULL, NULL);
